var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다, 다이브 아웃!","JPN":"ダ、ダイブアウト！","ENG":"D-Dive out!","TWN":"躍，躍出！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"양자터널 통과를 완료했습니다!","JPN":"量子トンネル通過が完了しました！","ENG":"We've passed through the quantum tunnel!","TWN":"已通過量子通道！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"레이더...... 아, 아니, 수정구도 깨끗합니다.","JPN":"レーダー……あ、いや、水晶玉もきれいです。","ENG":"The radar... I-I mean, the crystal ball is all clear as well.","TWN":"雷達……啊，不對，水晶球也很乾淨。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"침식파나 그림자 추적자의 징조도 보이지 않습니다.","JPN":"侵食波やシャドウ追跡者の兆候も見られません。","ENG":"No signs of corruption rays or shadow chasers either.","TWN":"沒有出現侵蝕波和暗影追兵的徵兆。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......쟤 뭐라는 거야? 수정구가 어쨌다고?","JPN":"……あいつ何言ってるの？　水晶玉が何だって？","ENG":"What is she talking about? Crystal ball? What?","TWN":"……那個人說什麼？什麼水晶球？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......문제없다는 것만 이해하면 된다. 그 외에는 신경 쓰지 말도록.","JPN":"……問題ないということだけ理解すれば良い。それ以外は気にするな。","ENG":"It just means there are no issues. No need to pay attention to any of the other rubbish she says.","TWN":"……妳只要理解成沒問題的意思就好了，其他的妳不用聽進去。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다 첫 고비는 넘겼군. 이제 어쩔 생각이지?","JPN":"それより、最初のヤマは越えたな。これからはどうするつもりだ？","ENG":"Anyway, so we've turned one corner. What now?","TWN":"我們算是通過第一個難關了。現在要做什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......양자터널을 이용한 다이브는 도착지 오차율이 커.","JPN":"……量子トンネルを利用したダイブは到着地の誤差率が大きい。","ENG":"A quantum dive has a large margin of error when it comes to arriving at the right destination.","TWN":"……利用量子通道的躍入，到達目的地的誤差率很高。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"일단은 이 근방을 수색하면서 리플레이서 놈들이 어디 있는지 확인해야지.","JPN":"一旦はこの辺を捜索しながら、リプレイサーのやつらがどこにいるのか確認しましょう。","ENG":"For now, we’ll have to search the area and see if we can locate the Replacers.","TWN":"先偵查附近區域，確定克隆集團的位置。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 다음엔?","JPN":"その次は？","ENG":"And then?","TWN":"然後呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 인자 전송기를 찾아서 파괴해야 해.","JPN":"リプレイサー・ファクター伝送機を探して破壊する。","ENG":"We’ll have to find the Replacer Factor transmitter and destroy it.","TWN":"找到克隆因子傳輸機並破壞掉它。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 인자 전송기?","JPN":"リプレイサー・ファクター伝送機？","ENG":"Replacer Factor transmitter?","TWN":"克隆因子傳輸機？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"재미있는 이름이네요.","JPN":"面白い名前ですね。","ENG":"Sounds interesting.","TWN":"真是個有趣的名字呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"양자터널을 빠져 나오는 동안 리플레이서 비숍이 전해 준 데이터를 조금 더 분석해 봤어.","JPN":"量子トンネルを通る間、リプレイサー・ビショップからもらったデータをもう少し分析してみたの。","ENG":"While we were passing through the quantum tunnel, I had a chance to analyze the Replacer Bishop’s data a little more.","TWN":"從量子通道出來的時候，我又分析了一下克隆·大主教傳來的資料。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자료에 따르면, 재생하는 로스트 쉽을 포함한 모든 이상현상의 원인은......","JPN":"資料によると、再生するロストシップを含む全ての異常現象の原因は……","ENG":"According to the data, all of these phenomena including the regenerating Lost Ships are...","TWN":"從資料上來看，可再生的失落艦船和其他異常現象出現的原因是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서가 만든 <color=#ffd34c>시스템 테라사이드</color>야.","JPN":"リプレイサーが作った<color=#ffd34c>テラサイドシステム</color>ね。","ENG":"Something called the <color=#ffd34c>System Terraside</color> created by the Replacer.","TWN":"克隆集團製造的<color=#ffd34c>特拉賽德系統</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그게 뭔데?","JPN":"……何それ？","ENG":"What’s that?","TWN":"……那是什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"간단히 말하면 일종의 역 테라포밍 시스템 같은 거야.","JPN":"簡単に言うと、ある種の逆テラフォーミング・システムみたいなものよ。","ENG":"In short, it's kind of like a reverse terraforming system.","TWN":"簡單來說就是一種反地球化的系統。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"현실 세계를 이면세계와 비슷한 환경으로 만드는......","JPN":"現実世界を裏世界に似た環境にするような……","ENG":"It’s supposed to turn reality into an environment similar to the Counterside...","TWN":"把現世變成和異界一樣的環境……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……なに？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"시스템 테라사이드는 두 가지의 독립적인 시스템으로 구성되어 있어.","JPN":"テラサイドシステムは二つの独立したシステムで構成されている。","ENG":"System Terraside is comprised of two independent systems.","TWN":"特拉賽德系統由兩個獨立的系統構成。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하나는 아마도 로스트 쉽을 통해 습득했을 것으로 추정되는 불멸체 시스템.","JPN":"一つは、おそらくロストシップを通じて習得したものと見られる不滅体システム。","ENG":"One is the Immortal System, which they likely acquired through the Lost Ship.","TWN":"一個可能是通過失落艦船掌握的不滅者系統。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"또 하나는 리플레이서 인자 전송 시스템이야.","JPN":"もう一つはリプレイサー・ファクター伝送システム。","ENG":"The other is the Replacer Factor Transmission System.","TWN":"另一個則是克隆因子傳輸系統。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이름만 들어도 감이 오지?","JPN":"名前だけでわかるよね？","ENG":"The names are pretty telling, right?","TWN":"光聽名字就有感覺了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"불멸체 시스템은 코어가 대상을 구성하는 원자 구성요소를 전부 마킹한 다음, 특정 시점으로 되돌리는 기술이야.","JPN":"不滅体システムは、コアが対象を構成する原子構成要素を全部マーキングした上で、\\n特定の時点に戻す技術よ。","ENG":"In the Immortal System, the core marks all the atomic components comprising the subject and reverses them to a certain point in time.","TWN":"不滅者系統是通過核心，標記對象的所有原子構成要素，使其能回溯到特定時間點的技術。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"파괴한 로스트 쉽이 다시 재생되는 이유지.","JPN":"破壊したロストシップが再生されるわけね。","ENG":"That’s how the Lost Ships managed to keep regenerating.","TWN":"這就是被破壞的失落艦船可以再生的原因。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"원자......?","JPN":"原子……？","ENG":"Atoms?","TWN":"原子……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잘은 모르지만 그거 엄청 많지 않아?","JPN":"詳しくはないけど、それってすごい数じゃない？","ENG":"I don’t know much about science, but aren’t there like gazillions of them?","TWN":"雖然我聽不太懂，但原子不是很多嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"사람 몸을 구성하는 원자수가 대략 10의 28승 개 정도 될 테니까......","JPN":"人の体を構成する原子の数が、おおよそ\\n10の28乗くらいだろうから……","ENG":"The human body is comprised of roughly 10^28 atoms, so...","TWN":"構成人體的原子數大約有10的28次方個……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 많은 로스트 쉽을 다 복구하려면, 물론 그보다는 많겠지.","JPN":"おびただしい数のロストシップをすべて復旧するなら、もちろんそれよりは多いでしょうね。","ENG":"Regenerating all those Lost Ships will involve even more atoms.","TWN":"而要復原那麼多的失落艦船，原子數當然也就更多了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말 그대로 천문학적인 숫자네요.","JPN":"言葉通り、天文学的な数ですね。","ENG":"That sure sounds like an astronomical figure.","TWN":"是個不折不扣的天文數字呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그걸 다 마킹해서 원격으로 컨트롤한다는 게 가능한가요?","JPN":"それを全部マーキングして遠隔でコントロールすることなんて、できるものなんですか？","ENG":"Is it possible to mark all those and control them remotely?","TWN":"但真的有可能標記這麼多原子，並且遠端控制它們嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 로스트 쉽 기술인 거지.","JPN":"だからこそ、ロストシップ技術なの。","ENG":"It would be, with the Lost Ship's technology.","TWN":"所以這就是失落艦船的技術啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"물론 결점도 많아.","JPN":"もちろん欠点も多い。","ENG":"But there are also many gaps.","TWN":"當然，它也有很多缺點。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"적용 대상이 한정적이라거나, 소모 에너지가 엄청나다거나.","JPN":"適用対象が限定的とか、消耗エネルギーが凄まじいとか。","ENG":"For instance, the range of subjects may be limited, or it might consume tremendous amounts of energy.","TWN":"比如適用對象有限，或者耗能過大。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그중에 가장 큰 결점은 재생 컨트롤을 담당하는 불멸체 코어를 파괴하면 단말들도 일시에 붕괴한다는 거야.","JPN":"なかでも最大の欠点は、再生コントロールを担う不滅体コアを破壊すると、\\n端末も一気に崩壊するということよ。","ENG":"The biggest flaw would be that destroying the Immortal System Core that controls the regeneration would in turn break down all the terminals at once.","TWN":"而這之中最大的缺點，就是控制再生的不滅者核心如果遭到破壞，裝置也會同時崩壞。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뿌리를 자르면 가지가 말라 죽는 거군요.","JPN":"根を切ったら、枝が枯れて死ぬってわけですね。","ENG":"Cut off the roots to wither the stem, so to speak.","TWN":"把根切斷了，枝椏也會跟著枯死吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇지 않나요, 스승님?","JPN":"そうじゃありませんか、師匠？","ENG":"Isn’t that right, Master?","TWN":"對吧，師父？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......왜 나에게 묻는 거지?","JPN":"……なぜ私に聞くんだ？","ENG":"Why are you asking me?","TWN":"……為什麼要問我？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 글쎄요...... 왜일까요?","JPN":"ハハ、さて……なぜでしょうか？","ENG":"Haha... I don't know... I wonder why?","TWN":"哈哈，這個嘛……是為什麼呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"좋은 비유야.","JPN":"いい例えね。","ENG":"That’s a good analogy.","TWN":"很好的比喻。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"불멸체 코어는 그 특성상 대량의 에너지를 사용하기 때문에 에너지 공급체로부터 멀리 움직일 수가 없다고 해.","JPN":"不滅体コアはその特性上、大量のエネルギーを使うからエネルギー供給体から遠く離れることはできないと言われているの。","ENG":"By nature, the Immortal System Core uses tremendous amounts of energy, so it cannot move far from the energy source.","TWN":"而由於不滅者核心需要使用大量能量，所以不能離能量供應體太遠。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 뿌리라고 해도 크게 틀린 말은 아니겠지.","JPN":"だから、根元といってもあながち間違ってないわ。","ENG":"So in a way, it sort of is like roots.","TWN":"所以說它是根也沒錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 불멸체 단말인 로스트 쉽을 차원간 전송 통로로 삼아서 리플레이서 인자를 살포하는 게......","JPN":"そして不滅体端末であるロストシップを次元間伝送通路としてリプレイサ・ファクターを散布するのが……","ENG":"Meanwhile, the Lost Ships serve as the terminals for distributing the Replacer Factors across the interdimensional transmission paths.","TWN":"然後把作為不滅者裝置的失落艦船當作次元間的傳輸路徑，散播克隆因子的……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"바로 리플레이서 인자 전송 시스템이야.","JPN":"リプレイサー・ファクター伝送システムなの。","ENG":"And that’s what the Replacer Factor Transmission System is all about.","TWN":"就是克隆因子傳輸系統了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"사람들이 급성 침식 증후군을 일으키는 건 바로 이 녀석 때문이지.","JPN":"人々が急性侵食症候群を起こすのは、まさにそのせい。","ENG":"This was the cause behind the Acute Corruption Syndrome we've been seeing among the afflicted populations.","TWN":"就是這個東西引發了人們的急性侵蝕症候群。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 인자를 살포한다고요?","JPN":"リプレイサー・ファクターを散布する？","ENG":"They distribute the Replacer Factor?","TWN":"妳說散播克隆因子嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 혹시......","JPN":"じゃあ、もしかして……","ENG":"Then could it be...","TWN":"那麼或許……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"생각하는 게 맞을걸?","JPN":"想像どおりだと思う。","ENG":"It probably is what you're thinking.","TWN":"就是你想的那樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"과연......","JPN":"なるほど……","ENG":"I see...","TWN":"果然……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 선배? 무슨 이야기를 하는 거야?","JPN":"何よ、先輩。何の話？","ENG":"What do you mean, Shiyoon? What are you guys talking about?","TWN":"什麼啊，前輩？你在說什麼啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"침식 증후군은 일반적으로 CSE 4레벨 이상의 고준위 침식파에 노출되었을 때 발생합니다.","JPN":"侵食症候群は、一般的にCSE4レベル以上の高レベル侵食波にさらされたときに発生します。","ENG":"Normally, Corruption Syndrome occurs among those who have been exposed to powerful corruption rays of at least CSE Level 4.","TWN":"一般來說，侵蝕症候群是暴露於CSE4級以上的高能侵蝕波所引起。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런데 이번 이상현상이 발생한 지역의 CSE 레벨은 전혀 변동이 없었어요.","JPN":"しかし、今回の異常現象が発生した地域のCSEレベルにはまったく変動がありませんでした。","ENG":"But we didn’t see any changes to the CSE Levels in these areas.","TWN":"但是這次發生異常現象的地方，CSE等級完全沒有變化。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 어째서 침식 증후군이 벌어진 걸까요?","JPN":"では、どうして侵食症候群が起こったのでしょうか。","ENG":"Which begs the question, how did these cases of Corruption Syndrome come about?","TWN":"那麼侵蝕症候群是怎麼發生的呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건......","JPN":"あれは……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그건 침식 증후군이 아니라 리플레이서 인자 감염으로 인한 변이 현상이기 때문이야.","JPN":"それは侵食症候群じゃなくて、リプレイサー・ファクター感染による変異現象だから。","ENG":"It’s because what we’ve seen is in fact not the Corruption Syndrome, but instead a mutation caused by Replacer Factor contamination.","TWN":"那不是侵蝕症候群，而是因為克隆因子感染引發的變異現象。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐......?!","JPN":"なんだって……！？","ENG":"What?!","TWN":"什麼……？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 놈들이 인간 - 침식체 간의 융합체를 생산한다는 사실은 알지?","JPN":"リプレイサーのやつらが人間と侵食体間の融合体を生産するということは知ってるでしょ？","ENG":"You're familiar with the fact that the Replacers have been producing human-C.O. hybrids, right?","TWN":"克隆集團生產的是一種人和侵蝕體之間的融合體，這妳是知道的吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 시스템을 사용하면 한 명, 한 명 복잡한 시술 과정을 거칠 필요 없이 단숨에 대규모의 융합 변이를 일으킬 수 있어.","JPN":"そのシステムを使えば、一人一人に複雑な施術を施さなくても、一気に大規模な融合変異を起こすことができるの。","ENG":"With this system, they can cause these mutations en masse without having to perform complex procedures on each individual.","TWN":"而使用這個系統，就不再需要一個個來進行複雜的手術，而是可以一次性完成大規模的融合變異。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"물론 성공률은 일반적인 경우보다 훨씬 낮아서, 대부분은 변이 과정에서 침식체로 붕괴되어 버리겠지만.","JPN":"もちろん成功率は一般的な場合よりはるかに低く、大部分は変異の過程で侵食体として崩壊してしまうだろうけどね。","ENG":"Of course, the success rate is a lot lower, so most folks will collapse into a C.O. during the mutation.","TWN":"當然成功率比一般情況低，大部分的人都會崩壞成侵蝕體。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"KS1에서 리플레이서 나이트와 처음 싸웠을 때 살포했던 안개와 비슷하군요.","JPN":"KS1でリプレイサー・ナイトと初めて戦ったときに散布した霧と似ていますね。","ENG":"It’s sort of like the fog they sprayed when we fought the Replacer Knight for the first time at KS1.","TWN":"在KS-1和克隆·騎士戰鬥時，他們散播的煙霧就和這個很相似。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 그런 셈이지. 작용범위가 엄청나게 넓다는 점을 제외하면 말이야.","JPN":"まあ、そんなところね。作用範囲が非常に広いという点を除けば。","ENG":"Something like that. Except the effective range of this is a whole lot wider.","TWN":"嗯，算是吧。除了適用範圍大很多以外。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 그 불멸체인가 하는 걸 먼저 부숴 버리면 안 돼?","JPN":"じゃあ、その不滅体とやらを先に壊しちゃダメなの？","ENG":"Then can't we just smash that Immortal System or whatever it is?","TWN":"那先破壞不滅者不就行了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그것만 처리하면 끝이라며?","JPN":"それさえ始末すれば、おしまいなんでしょ？","ENG":"Didn’t you say getting rid of that would do the trick?","TWN":"只要把那個處理掉就結束了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나도 그랬으면 좋겠지만......","JPN":"そうだといいんだけど……","ENG":"I wish it were that simple...","TWN":"我也希望能這樣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아쉽게도 코어는 자체적인 스텔스 기능으로 숨겨져 있어.","JPN":"残念ながら、コアは独自のステルス機能によって隠されているのよね。","ENG":"But unfortunately, the core remains hidden thanks to its own stealth feature.","TWN":"但可惜的是，核心被自身的隱形功能隱藏起來了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너희 구닥다리 함선의 색적 시스템으로는 정확한 위치를 찾는 게 불가능해.","JPN":"あんたらのおんぼろ艦船の\\n索敵システムじゃ、正確な位置を見つけられない。","ENG":"It’s impossible to pinpoint its location with the outdated search system on your piece of junk ship.","TWN":"憑你們這艘老古董的偵查系統，是不可能找到它的正確位置的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"구닥다리라서 죄송하네요!","JPN":"ええ、おんぼろでわるうございました！","ENG":"Well, jeez! We're sorry this piece of junk is all we got!","TWN":"我們的船是老古董真是抱歉喔！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"여하튼 그래서 불멸체 코어를 찾으려면 우선 리플레이서 인자 전송기를 파괴해야 해.","JPN":"とにかく、そういうわけで不滅体コアを探すには、まずリプレイサー・ファクター伝送機を破壊しなければならないの。","ENG":"Anyway, that’s why we need to destroy the Replacer Factor transmitter first in order to find the Immortal System Core.","TWN":"無論如何，想要找出不滅者核心，就得先破壞克隆因子傳輸機。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"왜냐하면 인자 전송기가 제공하는 대량의 리플레이서 인자 그 자체가 불멸체 코어의 주 에너지원이거든.","JPN":"なぜなら、ファクター伝送機から提供する大量のリプレイサー・ファクター自体が、不滅体コアの主なエネルギー源だからね。","ENG":"Because the massive amounts of Replacer Factor supplied by the transmitter is in fact the main energy source for the Immortal System Core.","TWN":"畢竟因子傳輸和提供的大量克隆因子就是不滅者核心的主要能量來源。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그게 가능해?","JPN":"……そんなのあり得るの？","ENG":"How’s that even possible?","TWN":"……那做得到嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 인자라는 건 사실 이터니움 합금으로 만든 일종의 나노머신이야.","JPN":"リプレイサー・ファクターというのは、実はエタニウム合金で作ったある種のナノマシンなの。","ENG":"Replacer Factors are actually sort of like nanomachines made of Eternium alloy.","TWN":"所謂克隆因子，其實就是永恆之金合金做成的奈米機器。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"구성요소인 이터니움을 에너지로 변환한다고 생각하면 말이 안 될 것도 없지.","JPN":"構成要素であるエタニウムをエネルギーに変換するとしたら、あり得ないことでもないでしょうね。","ENG":"So you basically convert the Eternium into energy. That’s hardly impossible.","TWN":"作為構成要素的永恆之金，也不是不可能轉化為能量。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그런가......?","JPN":"そ、そうかな……？","ENG":"I-is that right?","TWN":"是、是嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......알겠다.","JPN":"……了解した。","ENG":"Duly noted.","TWN":"……知道了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 우선 그 인자 전송기라는 걸 찾아야겠군.","JPN":"じゃあ、まずはそのファクター伝送機とやらを探さないといけないんだな。","ENG":"Then we should seek out this transmitter first.","TWN":"那麼首先要找到因子傳輸機。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 함선의 장거리 색적 시스템을 사용할 경우 적에게 발각될 수 있다.","JPN":"だけど、艦船の長距離索敵システムを使用すると、敵に発覚する恐れがある。","ENG":"However, using the ship's standoff ISR system may compromise our location.","TWN":"但是使用艦船的遠距離偵察系統很容易被敵人發現。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"괜히 상대가 쓸데없는 경계심을 가지도록 할 필요는 없겠지.","JPN":"相手に無駄な警戒心を持たせる必要もないだろう。","ENG":"There’s no need to heighten the enemy's alertness unnecessarily.","TWN":"沒必要引起對方的戒備。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러니 다들 소규모로 흩어져서 직접 적의 위치를 탐색하도록 한다.","JPN":"だからみんな散らばって、直接敵の位置を探索するとしよう。","ENG":"So everyone will split up into smaller groups and locate the enemy ourselves.","TWN":"所以大家分散開來，直接搜索敵人位置。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"탐색 과정에서 주위에 있는 침식체들과 조우할 경우, 최대한 조용하게 처리할 것.","JPN":"探索の過程で周囲の侵食体に遭遇した場合は、できるだけ静かに始末すること。","ENG":"Should you encounter any C.O. during the search, dispatch of them as quietly as possible.","TWN":"如果搜索中遇到侵蝕體的話，盡可能地安靜處理掉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 수상한 지역을 발견하면 무리하지 말고 즉시 보고한 후 퇴각하도록.","JPN":"そして怪しい地域を見つけたら直ちに報告した後、無理せず退却するように。","ENG":"If you find anything suspicious, do not engage beyond your capability. Instead, report your findings immediately and fall back.","TWN":"發現可疑區域的話不要勉強，立即報告然後撤退。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이상이다.","JPN":"以上だ。","ENG":"That’s all.","TWN":"完畢！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};